"use client";

import { useState } from "react";
import Link from "next/link";
import { motion } from "framer-motion";
import {
  ArrowRight,
  Edit2,
  Plus,
  Calendar,
  Clock,
  Phone,
  CalendarDays,
  StickyNote,
  CalendarX,
} from "lucide-react";
import { cn } from "@/lib/cn";
import type {
  AppointmentStatus,
  CustomerProfile,
} from "@/lib/data/mock/customerProfiles";

const statusConfig: Record<
  AppointmentStatus,
  { label: string; color: string; bg: string }
> = {
  pending: { label: "رزرو شده", color: "text-[#3B82F6]", bg: "bg-[#3B82F6]/10" },
  confirmed: { label: "تأیید شده", color: "text-[#4CAF82]", bg: "bg-[#4CAF82]/10" },
  completed: { label: "انجام شده", color: "text-[#A09880]", bg: "bg-[#A09880]/10" },
  cancelled: { label: "لغو شده", color: "text-[#E05555]", bg: "bg-[#E05555]/10" },
  no_show: { label: "غیبت", color: "text-[#E8A84C]", bg: "bg-[#E8A84C]/10" },
};

function getAvatarColor(name: string): string {
  const colors = [
    "from-[#C9A96E] to-[#E8C98A]",
    "from-[#3B82F6] to-[#60A5FA]",
    "from-[#4CAF82] to-[#6FCF97]",
  ];
  const index = name.charCodeAt(0) % colors.length;
  return colors[index];
}

type Tab = "upcoming" | "history";

interface CustomerProfileClientProps {
  customer: CustomerProfile;
}

export default function CustomerProfileClient({
  customer,
}: CustomerProfileClientProps) {
  const [activeTab, setActiveTab] = useState<Tab>("upcoming");

  const appointments =
    activeTab === "upcoming"
      ? customer.upcomingAppointments
      : customer.pastAppointments;

  return (
    <div className="space-y-6">
      <Link
        href="/admin/customers"
        className="inline-flex items-center gap-2 text-sm text-[#A09880] hover:text-[#C9A96E] transition-colors"
      >
        <ArrowRight size={16} />
        بازگشت به لیست مشتریان
      </Link>

      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        className="rounded-2xl bg-white/5 backdrop-blur-md border border-white/10 p-6"
      >
        <div className="flex flex-col md:flex-row md:items-start gap-6">
          <div
            className={cn(
              "w-20 h-20 rounded-2xl bg-gradient-to-br flex items-center justify-center text-[#0A0A0F] text-3xl font-bold",
              getAvatarColor(customer.name)
            )}
          >
            {customer.name.charAt(0)}
          </div>

          <div className="flex-1">
            <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4 mb-4">
              <div>
                <h1 className="text-2xl font-bold text-[#F5F0E8] mb-1">
                  {customer.name}
                </h1>
                <div className="flex items-center gap-2 text-[#A09880]">
                  <Phone size={14} />
                  <span dir="ltr">{customer.phone}</span>
                </div>
              </div>

              <div className="flex items-center gap-3">
                <button className="btn-outline-gold px-4 py-2 text-sm font-medium flex items-center gap-2">
                  <Edit2 size={16} />
                  ویرایش
                </button>
                <button className="btn-gold px-4 py-2 text-sm font-bold flex items-center gap-2">
                  <Plus size={16} />
                  نوبت جدید
                </button>
              </div>
            </div>

            <div className="flex flex-wrap gap-4 text-sm">
              <div className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-white/5">
                <CalendarDays size={14} className="text-[#C9A96E]" />
                <span className="text-[#A09880]">تاریخ عضویت:</span>
                <span className="text-[#F5F0E8]">{customer.joinDate}</span>
              </div>
              {customer.gender && (
                <div className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-white/5">
                  <span className="text-[#A09880]">جنسیت:</span>
                  <span className="text-[#F5F0E8]">{customer.gender}</span>
                </div>
              )}
            </div>

            {customer.notes && (
              <div className="mt-4 p-4 rounded-xl bg-white/5 border border-white/5">
                <div className="flex items-center gap-2 text-[#C9A96E] mb-2">
                  <StickyNote size={14} />
                  <span className="text-xs font-medium">یادداشت مدیر</span>
                </div>
                <p className="text-sm text-[#A09880]">{customer.notes}</p>
              </div>
            )}
          </div>
        </div>
      </motion.div>

      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.1 }}
        className="rounded-2xl bg-white/5 backdrop-blur-md border border-white/10 overflow-hidden"
      >
        <div className="flex border-b border-[#2A2A3A]">
          <button
            onClick={() => setActiveTab("upcoming")}
            className={cn(
              "flex-1 py-4 text-sm font-medium transition-colors relative",
              activeTab === "upcoming"
                ? "text-[#C9A96E]"
                : "text-[#A09880] hover:text-[#F5F0E8]"
            )}
          >
            نوبت‌های آینده
            {activeTab === "upcoming" && (
              <motion.div
                layoutId="activeTab"
                className="absolute bottom-0 right-0 left-0 h-0.5 bg-[#C9A96E]"
              />
            )}
          </button>
          <button
            onClick={() => setActiveTab("history")}
            className={cn(
              "flex-1 py-4 text-sm font-medium transition-colors relative",
              activeTab === "history"
                ? "text-[#C9A96E]"
                : "text-[#A09880] hover:text-[#F5F0E8]"
            )}
          >
            تاریخچه نوبت‌ها
            {activeTab === "history" && (
              <motion.div
                layoutId="activeTab"
                className="absolute bottom-0 right-0 left-0 h-0.5 bg-[#C9A96E]"
              />
            )}
          </button>
        </div>

        <div className="p-4">
          {appointments.length === 0 ? (
            <div className="py-12 text-center">
              <CalendarX size={48} className="mx-auto text-[#A09880] mb-4" />
              <h3 className="text-lg font-bold text-[#F5F0E8] mb-2">
                {activeTab === "upcoming"
                  ? "نوبت آینده‌ای ندارد"
                  : "سابقه‌ای وجود ندارد"}
              </h3>
              <p className="text-sm text-[#A09880] mb-6">
                {activeTab === "upcoming"
                  ? "برای این مشتری هنوز نوبتی ثبت نشده است"
                  : "این مشتری هنوز نوبتی نگرفته است"}
              </p>
              <button className="btn-gold px-6 py-2.5 text-sm font-bold">
                ثبت اولین نوبت
              </button>
            </div>
          ) : (
            <div className="space-y-3">
              {appointments.map((apt, i) => {
                const status = statusConfig[apt.status];
                return (
                  <motion.div
                    key={apt.id}
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: i * 0.05 }}
                    className="flex items-center gap-4 p-4 rounded-xl bg-white/5 hover:bg-white/[0.08] transition-colors"
                  >
                    <div className="text-center min-w-[60px]">
                      <div className="flex items-center justify-center gap-1 text-sm text-[#C9A96E]">
                        <Calendar size={12} />
                        {apt.date.split("/").slice(1).join("/")}
                      </div>
                      <div className="flex items-center justify-center gap-1 text-xs text-[#A09880] mt-1">
                        <Clock size={10} />
                        {apt.time}
                      </div>
                    </div>

                    <div className="w-px h-10 bg-[#2A2A3A]" />

                    <div className="flex-1">
                      <p className="font-medium text-[#F5F0E8]">
                        {apt.serviceName}
                      </p>
                      <p className="text-xs text-[#A09880]">{apt.staffName}</p>
                    </div>

                    <span
                      className={cn(
                        "px-2.5 py-1 rounded-lg text-xs font-medium",
                        status.bg,
                        status.color
                      )}
                    >
                      {status.label}
                    </span>
                  </motion.div>
                );
              })}
            </div>
          )}
        </div>
      </motion.div>
    </div>
  );
}

import CustomerProfileClient from "./CustomerProfileClient";
import {
  getCustomerProfileById,
  staticCustomerIds,
} from "@/lib/data/mock/customerProfiles";

export function generateStaticParams() {
  return staticCustomerIds.map((id) => ({ id }));
}

interface CustomerProfilePageProps {
  params: Promise<{ id: string }>;
}

export default async function CustomerProfilePage({
  params,
}: CustomerProfilePageProps) {
  const { id } = await params;
  const customer = getCustomerProfileById(id);

  return <CustomerProfileClient customer={customer} />;
}
